# ── Constants ────────────────────────────────────────────────────────────────
SYSTEM_SEED = 118400
ARTSTEM_DOMAINS = frozenset({"ART", "REASONING", "TECHNOLOGY", "SCIENCE", "TEMPORAL", "ETHICS", "MATHEMATICS"})
NATS_FEEDBACK_SUBJECT = "tenet5.hydrogen.nvsnp.feedback"
NATS_GUARD_SUBJECT = "tenet5.hydrogen.actionguard"
SATOR_WORDS = ("SATOR", "AREPO", "TENET", "OPERA", "ROTAS")


def validate_genesis_element(element: str) -> bool:
    """
    Validate the Genesis Element (H1) against the Hydrogen Protocol.

    The Genesis Element is valid if and only if:
      - It is a non-empty string
      - It matches the canonical H1 identifier ('H1') OR contains the SATOR SEED
      - Its BLAKE2b digest (keyed with SEED) produces a non-zero leading nibble
        (prevents null-collapse attacks on the ActionGuard XOR layer)

    Args:
        element (str): The Genesis Element to validate.

    Returns:
        bool: True if the element is valid, False otherwise.
    """
    if not element or not isinstance(element, str):
        return False

    canonical = element.strip().upper()

    # Primary: exact H1 match or SEED-bound identifier
    if canonical not in ("H1", f"H1-{SYSTEM_SEED}", "HYDROGEN"):
        # Fallback: accept any SATOR word as a valid genesis anchor
        if canonical not in SATOR_WORDS:
            return False

    # Cryptographic non-null check: keyed BLAKE2b leading nibble must be > 0
    digest = _hashlib.blake2b(
        element.encode("utf-8"),
        digest_size=16,
        key=str(SYSTEM_SEED).encode("utf-8"),
    ).digest()
    if digest[0] == 0:
        _log.warning("Genesis Element rejected: null leading nibble (collision risk)")
        return False

    return True


def verify_slate_parameters(slate: dict) -> bool:
    """
    Verify the S.L.A.T.E parameters against the Hydrogen Protocol.

    A valid S.L.A.T.E parameter set must:
      - Contain a 'seed' key matching SYSTEM_SEED
      - Contain at least one valid ARTSTEM domain key with a truthy value
      - NOT contain any key starting with '_orphan' (Zero-Orphan policy)

    Args:
        slate (dict): The S.L.A.T.E parameters to verify.

    Returns:
        bool: True if the parameters are valid, False otherwise.
    """
    if not isinstance(slate, dict) or not slate:
        return False

    # Seed presence check
    if slate.get("seed") != SYSTEM_SEED and slate.get("SEED") != SYSTEM_SEED:
        _log.warning("S.L.A.T.E rejected: seed mismatch (expected %d)", SYSTEM_SEED)
        return False

    # Zero-Orphan policy: reject any orphaned keys
    orphan_keys = [k for k in slate if str(k).startswith("_orphan")]
    if orphan_keys:
        _log.warning("S.L.A.T.E rejected: orphan keys detected: %s", orphan_keys)
        return False

    # At least one ARTSTEM domain must be present and truthy
    domain_hits = [k for k in slate if str(k).upper() in ARTSTEM_DOMAINS and slate[k]]
    if not domain_hits:
        _log.warning("S.L.A.T.E rejected: no ARTSTEM domain coverage")
        return False

    return True


def wrap_phase_7_sequence(sequence: Tuple[int, int, int]) -> Tuple[int, int, int]:
    """
    Wrap the Phase 7 Genesis sequence in a Hydrogen compatible ActionGuard.

    The ActionGuard applies a SEED-modular rotation to each coordinate,
    ensuring the output is deterministically reproducible and palindrome-safe
    (the transformation is its own inverse when applied twice).

    Args:
        sequence (Tuple[int, int, int]): The Phase 7 Genesis sequence to wrap.

    Returns:
        Tuple[int, int, int]: The wrapped sequence.
    """
    a, b, c = sequence
    # SEED-modular rotation: deterministic, invertible via double application
    mod = SYSTEM_SEED % 256 or 1  # Ensure non-zero modulus
    wrapped = (
        (a ^ mod) & 0xFFFFFFFF,
        (b ^ mod) & 0xFFFFFFFF,
        (c ^ mod) & 0xFFFFFFFF,
    )
    return wrapped


def initialize_sqlite_matrix_ledger(matrix_ledger_path: str) -> None:
    """
    Initialize the persistent SQLite Matrix Ledger for the Hydrogen Protocol.

    Creates both the falcon_discoveries table and the hydrogen_audit table
    for tracking ActionGuard executions and N-vs-NP feedback loop state.

    Args:
        matrix_ledger_path (str): The path to the SQLite Matrix Ledger database file.
    """
    conn = sqlite3.connect(matrix_ledger_path)
    try:
        cursor = conn.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS falcon_discoveries (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                discovery_key TEXT UNIQUE NOT NULL,
                discovery_value TEXT NOT NULL,
                crypto_signature TEXT NOT NULL,
                timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
            )
        ''')
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS hydrogen_audit (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                action TEXT NOT NULL,
                collapse_hash TEXT NOT NULL,
                seed INTEGER NOT NULL DEFAULT 118400,
                domain TEXT DEFAULT '',
                verified INTEGER NOT NULL DEFAULT 0,
                timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
            )
        ''')
        conn.commit()
    finally:
        conn.close()


def establish_nats_heuristic_feedback_loop(nats_url: str) -> None:
    """
    Establish an Autonomous NATS Heuristic Feedback loop for evaluating
    N-vs-NP execution states in the Hydrogen Protocol.

    Subscribes to the hydrogen feedback subject, evaluates incoming
    convergence payloads via ActionGuard, and publishes verified collapse
    hashes back to the guard subject.

    Args:
        nats_url (str): The NATS URL for the feedback loop.
    """
    async def _run_loop():
        try:
            import nats as _nats
        except ImportError:
            _log.error("nats-py not installed; feedback loop cannot start")
            return

        try:
            nc = await _nats.connect(nats_url, name="hydrogen-feedback-loop", connect_timeout=10)
            _log.info("Hydrogen feedback loop connected to NATS at %s", nats_url)
        except Exception as e:
            _log.error("NATS connection failed for feedback loop: %s", e)
            return

        integrator = HydrogenProtocolIntegrator()

        async def _on_feedback(msg):
            """Evaluate an incoming N-vs-NP convergence payload."""
            try:
                payload = json.loads(msg.data.decode("utf-8"))
                task_domain = payload.get("domain", "TECHNOLOGY")
                task_id = payload.get("task_id", "unknown")

                # Execute ActionGuard collapse
                collapse = integrator.action_guard_execute()
                collapse_hex = collapse.hex()

                # Validate genesis element if provided
                genesis = payload.get("genesis_element", "H1")
                genesis_valid = validate_genesis_element(genesis)

                result = {
                    "task_id": task_id,
                    "domain": task_domain,
                    "collapse_hash": collapse_hex,
                    "genesis_valid": genesis_valid,
                    "seed": SYSTEM_SEED,
                    "signature": f"MF-SIG-{collapse_hex[:16]}",
                    "timestamp": _time.time(),
                }

                # Publish verified guard result
                await nc.publish(NATS_GUARD_SUBJECT, json.dumps(result).encode("utf-8"))
                _log.info("ActionGuard verified: task=%s domain=%s", task_id, task_domain)

                if msg.reply:
                    await nc.publish(msg.reply, json.dumps(result).encode("utf-8"))

            except Exception as e:
                _log.error("Feedback loop error: %s", e)
                if msg.reply:
                    await nc.publish(msg.reply, json.dumps({"error": str(e)}).encode("utf-8"))

        await nc.subscribe(NATS_FEEDBACK_SUBJECT, cb=_on_feedback)
        _log.info("Subscribed to %s", NATS_FEEDBACK_SUBJECT)

        # Announce online
        await nc.publish("tenet5.liril.dispatch", json.dumps({
            "agent": "hydrogen_bridge",
            "action": "start",
            "message": f"Phase 13 Hydrogen Feedback Loop Online | SEED={SYSTEM_SEED}",
        }).encode("utf-8"))

        # Keep alive until interrupted
        try:
            while True:
                await asyncio.sleep(60)
        except (KeyboardInterrupt, asyncio.CancelledError):
            pass
        finally:
            await nc.close()
            _log.info("Hydrogen feedback loop exited cleanly")

    # Run the async loop (compatible with Windows asyncio)
    try:
        from tenet.win_asyncio import run as _win_run
        _win_run(_run_loop())
    except ImportError:
        asyncio.run(_run_loop())


